{
  "exports": {
    "default": {
      "name": "leftPad",
      "parameters": [
        {
          "description": "The value to pad. Numbers are coerced to strings.",
          "name": "str",
          "type": "string | number"
        },
        {
          "description": "The desired total length of the resulting padded string.",
          "name": "len",
          "type": "number"
        },
        {
          "default": " ",
          "description": "The character to use for padding. Defaults to a single space character. Numbers are coerced to strings.",
          "name": "ch",
          "required": false,
          "type": "string | number"
        }
      ],
      "returns": {
        "description": "The input string left-padded with the specified character to at least the specified length.",
        "type": "string"
      },
      "signature": "leftPad(str: string | number, len: number, ch?: string | number) => string",
      "type": "function"
    }
  },
  "module": "left-pad"
}

{
  "leftPad": {
    "coercion": "If `str` is a number, it is converted to its string representation before padding. If `ch` is a number, it is converted to its string representation before use as the pad character.",
    "default_pad_character": "When `ch` is not provided or is undefined, a single ASCII space character (U+0020) is used as the pad character.",
    "description": "Pads the left side of a string with a padding character until the string reaches the target length.",
    "no_padding_needed": "If `str` is already equal to or longer than `len`, the original string (coerced to string if necessary) is returned unchanged, without any truncation.",
    "padding_logic": "The function computes how many characters need to be prepended to `str` to reach length `len`. It prepends copies of `ch` (or the first character of `ch` if `ch` is a multi-character string is not explicitly documented, but `ch` is documented as a character) to the left of `str` until the total length equals `len`.",
    "return_value": "Always returns a string regardless of the type of `str`."
  }
}

{
  "no_config_files": "The package has no configuration files, environment variables, or initialization options.",
  "parameters": {
    "ch_default": "The pad character `ch` defaults to a single space ' ' when not provided.",
    "len_default": "There is no default for `len`; it is a required positional parameter.",
    "str_default": "There is no default for `str`; it is a required positional parameter."
  }
}

{
  "module_format": "CommonJS module; the function is the module's default export (module.exports = leftPad).",
  "types": {
    "InputValue": "string | number — accepted types for the `str` argument",
    "Length": "number — the target total length of the padded result",
    "PadChar": "string | number | undefined — accepted types for the `ch` argument",
    "Result": "string — the padded string output"
  },
  "typescript_definition": "declare function leftPad(str: string | number, len: number, ch?: string | number): string; export = leftPad;"
}

{
  "documented_errors": "No explicit error types or thrown exceptions are documented in the public API for v1.1.3.",
  "implicit_behavior": {
    "invalid_len": "Passing non-numeric values for `len` may produce unexpected results but no specific error is documented.",
    "null_ch": "Behavior when `null` is passed for `ch` is not documented.",
    "null_str": "Behavior when `null` is passed for `str` is not documented; coercion behavior would depend on implementation."
  },
  "notes": "The package does not document any thrown Error objects, rejected Promises, or error codes. It is a synchronous, non-throwing utility by design intent."
}

{
  "scenarios": [
    {
      "description": "Pad a short string with default space character",
      "expected_output": "  foo",
      "id": "TC-01",
      "input": {
        "len": 5,
        "str": "foo"
      },
      "notes": "Two spaces prepended to reach length 5"
    },
    {
      "description": "Pad a string with a custom character",
      "expected_output": "00foo",
      "id": "TC-02",
      "input": {
        "ch": "0",
        "len": 5,
        "str": "foo"
      },
      "notes": "Two '0' characters prepended"
    },
    {
      "description": "String already equals target length",
      "expected_output": "hello",
      "id": "TC-03",
      "input": {
        "len": 5,
        "str": "hello"
      },
      "notes": "No padding added"
    },
    {
      "description": "String exceeds target length",
      "expected_output": "hello world",
      "id": "TC-04",
      "input": {
        "len": 5,
        "str": "hello world"
      },
      "notes": "No truncation; original string returned"
    },
    {
      "description": "Numeric str input",
      "expected_output": "00042",
      "id": "TC-05",
      "input": {
        "ch": "0",
        "len": 5,
        "str": 42
      },
      "notes": "Number coerced to '42', then padded"
    },
    {
      "description": "Numeric ch input",
      "expected_output": "007",
      "id": "TC-06",
      "input": {
        "ch": 0,
        "len": 3,
        "str": "7"
      },
      "notes": "ch=0 coerced to '0'"
    },
    {
      "description": "Empty string padded",
      "expected_output": "---",
      "id": "TC-07",
      "input": {
        "ch": "-",
        "len": 3,
        "str": ""
      },
      "notes": "Three dashes fill the entire length"
    },
    {
      "description": "len is 0",
      "expected_output": "hi",
      "id": "TC-08",
      "input": {
        "len": 0,
        "str": "hi"
      },
      "notes": "No padding, original string returned"
    },
    {
      "description": "ch omitted, defaults to space",
      "expected_output": "   x",
      "id": "TC-09",
      "input": {
        "len": 4,
        "str": "x"
      },
      "notes": "Three spaces prepended using default pad char"
    },
    {
      "description": "Pad with space character explicitly",
      "expected_output": "   ab",
      "id": "TC-10",
      "input": {
        "ch": " ",
        "len": 5,
        "str": "ab"
      },
      "notes": "Explicit space character behaves same as default"
    },
    {
      "description": "Single character string padded to length 1",
      "expected_output": "a",
      "id": "TC-11",
      "input": {
        "len": 1,
        "str": "a"
      },
      "notes": "Already at target length, no padding"
    },
    {
      "description": "Numeric str of 0",
      "expected_output": "000",
      "id": "TC-12",
      "input": {
        "ch": "0",
        "len": 3,
        "str": 0
      },
      "notes": "Number 0 coerced to '0', then padded to '000'"
    }
  ]
}
